def subarraySumEqualsK(data):
    nums, k = data.split('\n')[0].split(), int(data.split('\n')[1])
    nums = list(map(int, nums))
    count = 0
    n = len(nums)
    for start in range(n):
        current_sum = 0
        for end in range(start, n):
            current_sum += nums[end]
            if current_sum == k:
                count += 1
    return count

