#include <vector>
#include <unordered_map>
using namespace std;
class Solution {
    public:
    int subarraySumEqualsK(const vector<int>& data, int k) {
        unordered_map<int, int> sumCount;
        sumCount[0] = 1;
        int cumulativeSum = 0;
        int count = 0;
        for (int num : data) {
            cumulativeSum += num;
            if (sumCount.find(cumulativeSum - k) != sumCount.end()) {
                count += sumCount[cumulativeSum - k];
            }
            sumCount[cumulativeSum]++;
        }
        return count;
    }
}
